// src/context/AuthContext.js
import React, { createContext, useContext, useEffect, useState } from "react";
import {
  auth,
  signInWithGoogle,
  signUpWithEmail,
  loginWithEmail,
  resetPassword,
  logout,
  monitorAuthState,
} from "../firebase";

const AuthContext = createContext();

export function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [initializing, setInitializing] = useState(true);

  // Monitor authentication state
  useEffect(() => {
    const unsubscribe = monitorAuthState((currentUser) => {
      setUser(currentUser);
      setInitializing(false);
    });
    return () => unsubscribe && unsubscribe();
  }, []);

  // --- Auth Actions ---
  const loginWithGoogleAuth = async () => {
    const userData = await signInWithGoogle();
    setUser(userData);
  };

  const loginWithEmailAuth = async (email, password) => {
    const userData = await loginWithEmail(email, password);
    setUser(userData);
  };

  const signupWithEmailAuth = async (email, password) => {
    const userData = await signUpWithEmail(email, password);
    setUser(userData);
  };

  const resetPasswordAuth = async (email) => {
    await resetPassword(email);
  };

  const logoutAuth = async () => {
    await logout();
    setUser(null);
  };

  return (
    <AuthContext.Provider
      value={{
        user,
        initializing,
        loginWithGoogle: loginWithGoogleAuth,
        loginWithEmail: loginWithEmailAuth,
        signupWithEmail: signupWithEmailAuth,
        resetPassword: resetPasswordAuth,
        logout: logoutAuth,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
}

export const useAuth = () => useContext(AuthContext);
